"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[4376],{7361(i){i.exports=JSON.parse('{"tag":{"label":"coinjoin","permalink":"/tags/coinjoin","allTagsPath":"/tags","count":6,"items":[{"id":"summaries/privacy-as-a-spectrum","title":"Privacy as a Spectrum","description":"Privacy is not a feature you add to Bitcoin after the fact. It is a prerequisite for fungibility: the property that makes one satoshi interchangeable with any other. Without privacy, transactions become targets for censorship, surveillance, and discrimination. The blockchain is permanent; any link you create between your identity and your UTXOs cannot be undone.","permalink":"/summaries/privacy-as-a-spectrum"},{"id":"concepts/privacy-stacks","title":"Privacy Stacks","description":"Privacy in Bitcoin is not a single tool \u2014 it is a layered practice combining network hygiene, transaction obfuscation, and operational security (OPSEC). The goal is to selectively reveal data instead of broadcasting it by default.","permalink":"/concepts/privacy-stacks"},{"id":"comparisons/privacy-stacks","title":"Privacy Stacks \u2014 CoinJoin and No-KYC Acquisition","description":"Privacy in Bitcoin is not a single tool \u2014 it is a layered practice. This comparison focuses on the two most critical layers: how you acquire bitcoin without KYC and how you break the transaction graph after acquisition.","permalink":"/comparisons/privacy-stacks"},{"id":"entities/stonewall","title":"Stonewall","description":"Stonewall is a single-user privacy feature in Samourai Wallet that creates transactions resembling mini CoinJoins but without multiple parties. It confuses chain analysis heuristics.","permalink":"/entities/stonewall"},{"id":"queries/what-privacy-stack-should-i-use-for-mobile","title":"What Privacy Stack Should I Use for Mobile?","description":"Mobile devices are the weakest link in most bitcoiners\' privacy stacks. They broadcast location, run closed-source basebands, and constantly phone home to Apple or Google. This page maps a practical mobile privacy stack from OS to wallet.","permalink":"/queries/what-privacy-stack-should-i-use-for-mobile"},{"id":"entities/whirlpool","title":"Whirlpool","description":"Whirlpool is a zero-link CoinJoin implementation developed by Samourai Wallet. It breaks deterministic links between inputs and outputs, improving on-chain privacy.","permalink":"/entities/whirlpool"}],"unlisted":false}}')}}]);